setup(props, { slots, attrs }) {
  const nuxtApp = useNuxtApp()
  const payload = useComposableContext(nuxtApp).localePathPayload
  const switchLocalePath = useSwitchLocalePath(nuxtApp)

  const resolved = computed(() => {
    if (__I18N_STRICT_SEO__ && nuxtApp.isHydrating && Object.keys(payload ?? {}).length && !payload?.[props.locale]) {
      return '#'
    }
    return encodeURI(switchLocalePath(props.locale)) || (__I18N_STRICT_SEO__ && '#') || ''
  })

  const disabled = computed(() => (__I18N_STRICT_SEO__ && resolved.value === '#') || undefined)

  return () => h(NuxtLink, { ...attrs, 'to': resolved.value, 'data-i18n-disabled': disabled.value }, slots.default)
}

export async function resolveLayerVueI18nConfigInfo(ctx: I18nNuxtContext, nuxt = useNuxt()) {
  const res: Omit<FileMeta, 'cache'>[] = []

  // collect `installModule` config
  if (ctx.options.vueI18n && isAbsolute(ctx.options.vueI18n)) {
    const resolved = await findPath(ctx.options.vueI18n, { extensions: EXECUTABLE_EXTENSIONS })

    if (resolved) {
      res.push(resolveVueI18nConfigInfo(resolved, nuxt.vfs))
    }
  }

  for (const layer of ctx.i18nLayers) {
    const resolved = await findPath(layer.i18n.vueI18n || 'i18n.config', { cwd: layer.i18nDir, extensions: EXECUTABLE_EXTENSIONS })

    if (!resolved) {
      if (layer.i18n.vueI18n) {
        logger.warn(`Vue I18n configuration file \`${layer.i18n.vueI18n}\` not found in \`${layer.i18nDir}\`. Skipping...`)
      }
      continue
    }

    res.push(resolveVueI18nConfigInfo(resolved, nuxt.vfs))
  }

  return res
}

export function _useLocaleHead(ctx: ComposableContext, options: Required<I18nHeadOptions>): Ref<I18nHeadMetaInfo> {
  const metaObject = ref(_localeHead(createHeadContext(ctx, options)))

  if (import.meta.client) {
    const unsub = watch([() => ctx.router.currentRoute.value, () => ctx.getLocale()], () => {
      metaObject.value = _localeHead(createHeadContext(ctx, options))
      __I18N_STRICT_SEO__ && ctx.head?.patch(metaObject.value)
    })
    if (getCurrentScope()) {
      onScopeDispose(unsub)
    }
  }

  __I18N_STRICT_SEO__ && ctx.head?.patch(metaObject.value)

  return metaObject
}

function _createStatus() {
  const isTTY = process.stderr.isTTY;
  if (!isTTY) {
    return { update(_text: string) {}, done() {} };
  }
  let msg = "";
  let frame = 0;
  const render = () => {
    const spinner = _spinnerFrames[frame % _spinnerFrames.length];
    frame++;
    process.stderr.write(`\x1B[2K\r\x1B[2m${spinner} ${msg}\x1B[0m`);
  };
  const interval = setInterval(render, 80);
  return {
    update(text: string) {
      msg = text;
      render();
    },
    done() {
      clearInterval(interval);
      process.stderr.write("\x1B[2K\r");
    },
  };
}

export function toNodeHandler(app: H3): NodeHandler {
  if ((toNodeHandler as any)._isWarned !== true) {
    console.warn(
      `[h3] "toNodeHandler" export from h3 is deprecated. Please import "toNodeHandler" from "h3/node".`,
    );
    (toNodeHandler as any)._isWarned = true;
  }
  const _toNodeHandler = ((toNodeHandler as any)._toNodeHandler ??= () => {
    const _require = globalThis.process
      .getBuiltinModule("node:module")
      .createRequire(import.meta.url);
    return _require("srvx/node").toNodeHandler;
  })();
  return _toNodeHandler(app.fetch);
}

export function mockEvent(
  _request: string | URL | Request,
  options?: RequestInit & { h3?: H3EventContext },
): H3Event {
  let request: Request;
  if (options?.body && !(options as any).duplex) {
    (options as any).duplex = "half";
  }
  if (typeof _request === "string") {
    let url = _request;
    if (url[0] === "/") {
      url = `http://localhost${url}`;
    }
    request = new Request(url, options);
  } else if (options || _request instanceof URL) {
    request = new Request(_request, options);
  } else {
    request = _request;
  }
  return new H3Event(request);
}

export async function readMultipartFormData(event: H3Event): Promise<
  Array<{
    data: Uint8Array;
    name?: string;
    filename?: string;
    type?: string;
  }>
> {
  const formData = await event.req.formData();

  return Promise.all(
    [...formData.entries()].map(async ([key, value]) => {
      return typeof value === "object"
        ? {
            name: key,
            type: (value as Blob).type,
            filename: (value as File).name,
            data: await (value as Blob).bytes(),
          }
        : { name: key, data: new TextEncoder().encode(value) };
    }),
  );
}

export function setServerTiming(
  event: H3Event,
  name: string,
  opts?: { dur?: number; desc?: string },
): void {
  if (!_isValidToken(name)) {
    throw new TypeError(`Invalid Server-Timing metric name: ${name}`);
  }
  if (opts?.dur !== undefined && (!Number.isFinite(opts.dur) || opts.dur < 0)) {
    throw new TypeError(`Invalid Server-Timing duration: ${opts.dur}`);
  }
  const value =
    name +
    (opts?.desc ? `;desc="${_escapeDesc(opts.desc)}"` : "") +
    (opts?.dur !== undefined ? `;dur=${opts.dur}` : "");
  event.res.headers.append("server-timing", value);
  const ctx = event.context as H3EventContext;
  if (!Array.isArray(ctx.timing)) {
    ctx.timing = [];
  }
  ctx.timing.push({ name, ...opts });
}

export function getNetworkInterfaces(includeIPV6?: boolean): string[] {
  const addrs = new Set<string>();
  for (const details of Object.values(networkInterfaces())) {
    if (details) {
      for (const d of details) {
        if (
          !d.internal &&
          !(d.mac === "00:00:00:00:00:00") &&
          !d.address.startsWith("fe80::") &&
          !d.address.startsWith("169.254.") &&
          !(!includeIPV6 && (d.family === "IPv6" || +d.family === 6))
        ) {
          addrs.add(formatAddress(d));
        }
      }
    }
  }
  return [...addrs].sort();
}

